protected boolean validateInvoiceQuantityAgainstPurchaseLine(VendInvoiceInfoLine _vendInvoiceInfoLine)
{
    VendDocumentTableMap  parmHeader      = this.parmHeader;
    PurchParmUpdate       purchParmUpdate = parmHeader.purchParmUpdate();
    boolean               ok = false;
    int infologLineStart = infologLine() + 1;

    if (purchParmUpdate.SpecQty == PurchUpdate::FWFAccusInvoicePriceCorrection)
    {
        _vendInvoiceInfoLine.ReceiveNow = -_vendInvoiceInfoLine.ReceiveNow;
    }

    ok = next validateInvoiceQuantityAgainstPurchaseLine(_vendInvoiceInfoLine);

    if (purchParmUpdate.SpecQty == PurchUpdate::FWFAccusInvoicePriceCorrection)
    {
        _vendInvoiceInfoLine.ReceiveNow = -_vendInvoiceInfoLine.ReceiveNow;

        infolog.cut(infologLineStart, infologLine());
    }

    if (purchParmUpdate.SpecQty != PurchUpdate::FWFAccusInvoicePriceCorrection)
    {
        return ok;   
    }
    else
    {
        return true;
    }
}
